(function () {
    const swapContent = (target, html) => {
        if (!target) {
            return;
        }
        target.innerHTML = html;
    };

    const submitHandler = async (event) => {
        const form = event.target;
        const method = (form.getAttribute("hx-post") ? "POST" : (form.getAttribute("hx-get") ? "GET" : form.method || "GET")).toUpperCase();
        const url = form.getAttribute("hx-post") || form.getAttribute("hx-get") || form.action;

        if (!url || !form.hasAttribute("hx-post") && !form.hasAttribute("hx-get")) {
            return;
        }

        event.preventDefault();

        const targetSelector = form.getAttribute("hx-target");
        const target = targetSelector ? document.querySelector(targetSelector) : null;
        const swap = form.getAttribute("hx-swap") || "innerHTML";
        const formData = new FormData(form);
        const headers = { "X-Requested-With": "XMLHttpRequest" };

        const response = await fetch(url, {
            method,
            headers,
            body: method === "GET" ? undefined : formData,
        });

        const html = await response.text();
        if (swap === "none") {
            return;
        }
        swapContent(target, html);
    };

    document.addEventListener("submit", (event) => {
        const form = event.target;
        if (form.hasAttribute("hx-post") || form.hasAttribute("hx-get")) {
            submitHandler(event).catch(() => {});
        }
    });

    window.htmx = {
        process() {},
    };
})();
